scwin.f_ReqFieldChk = async function (workGb) {
  let vaildArray = [{
    id: "cust",
    name: "Customer",
    mandatory: true,
    length: 6
  }, {
    id: "contractno",
    name: "Contract No",
    mandatory: true,
    length: 11
  }, {
    id: "liner",
    name: "Liner Code",
    mandatory: false
  }, {
    id: "portFrom",
    name: "Loading",
    mandatory: true,
    length: 5
  }, {
    id: "portTo",
    name: "Discharge",
    mandatory: true,
    length: 5
  }, {
    id: "apdtFrom",
    name: "From Date",
    mandatory: true,
    length: 8,
    valid: "date",
    format: "YYYYMMDD"
  }, {
    id: "apdtTo",
    name: "To Date",
    mandatory: true,
    length: 8,
    valid: "date",
    format: "YYYYMMDD"
  }, {
    id: "item",
    name: "Item",
    mandatory: false
  }, {
    id: "fcode",
    name: "Freight",
    mandatory: true
  }, {
    id: "type",
    name: "Type",
    mandatory: true
  }, {
    id: "curr",
    name: "Currency",
    mandatory: true,
    length: 3
  }, {
    id: "amount",
    name: "Amount",
    mandatory: true,
    valid: "minNumber",
    minNumber: 1
  }, {
    id: "dg",
    name: "D/G",
    mandatory: true
  }];
  switch (workGb) {
    case "SEARCH":
      let chk1 = await $c.gus.cfValidate($p, tb_searchCondition);
      if (!chk1) {
        return false;
      } else {
        return true;
      }
      break;
    case "DEATAIL_SEARCH":
      let chk2 = await $c.gus.cfValidate($p, tb_DetailInfo);
      let chk3 = await $c.gus.cfValidateGrid($p, gr_DetailInfo, null, null, vaildArray, "Tariff Information");
      if (!chk2 || !chk3) {
        return false;
      } else {
        return true;
      }
      break;
    case "TARIFFLIST":
      let chk4 = await $c.gus.cfValidateGrid($p, gr_TariffList, null, null, vaildArray, "Tariff");
      if (!chk4) {
        return false;
      } else {
        return true;
      }
      break;
  }
};
