scwin.lc_contractno_onchange = function (e) {
  let curRow = ds_DetailInfo.getRowPosition();
  let rowJson = ds_DetailInfo.getRowJSON(curRow);
  let contractnoVal = rowJson.contractno;
  let contractnoTampVal = rowJson.contractnoTamp;
  if (contractnoVal != "선택") {
    if (contractnoTampVal != "") {
      ds_DetailInfo.setCellData(curRow, "contractnoTamp", contractnoVal);
    } else if (contractnoTampVal != contractnoVal) {
      ds_DetailInfo.setCellData(curRow, "contractnoTamp", contractnoVal);
    }
    ds_DetailInfo.setCellData(curRow, "contractnoTamp", contractnoVal);
  } else {
    if (contractnoTampVal != "") {
      ds_DetailInfo.setCellData(curRow, "contractno", contractnoTampVal);
    } else {
      ds_DetailInfo.setCellData(curRow, "contractnoTamp", contractnoVal);
    }
  }
};
scwin.lc_contractno_onblur = function (e) {
  let curRow = ds_DetailInfo.getRowPosition();
  let ctrtRow = ds_ctrtNo.getRowPosition();
  if (ds_DetailInfo.getCellData(curRow, "apdtFrom").trim() == "" || ds_DetailInfo.getCellData(curRow, "apdtTo").trim() == "") {
    ds_DetailInfo.setCellData(curRow, "apdtFrom", ds_ctrtNo.getCellData(ctrtRow, "ctrtStDt"));
    ds_DetailInfo.setCellData(curRow, "apdtTo", ds_ctrtNo.getCellData(ctrtRow, "ctrtEndDt"));
  }
};
scwin.gr_DetailInfo_ontextimageclick = function (rowIndex, columnIndex) {
  let columnId = this.getColumnID(columnIndex);
  switch (columnId) {
    case "cust":
      scwin.f_PopUpGrid("Customer", rowIndex, "F", "F");
      break;
    case "liner":
      scwin.f_PopUpGrid("Liner", rowIndex, "F", "F");
      break;
    case "portFrom":
      scwin.f_PopUpGrid("Loading", rowIndex, "F", "F");
      break;
    case "portTo":
      scwin.f_PopUpGrid("Discharge", rowIndex, "F", "F");
      break;
    case "item":
      scwin.f_PopUpGrid("Item", rowIndex, "F", "F");
      break;
    case "fcode":
      scwin.f_PopUpGrid("Freight", rowIndex, "F", "F");
      break;
    case "type":
      scwin.f_PopUpGrid("CNTR_TYPE", rowIndex, "F", "F");
      break;
    case "curr":
      scwin.f_PopUpGrid("Currency", rowIndex, "F", "F");
      break;
    default:
      break;
  }
};
scwin.gr_DetailInfo_onafteredit = function (rowIndex, columnIndex, value) {
  let columnId = this.getColumnID(columnIndex);
  let rowJson = ds_DetailInfo.getRowJSON(rowIndex);
  if (rowIndex >= 0 && ds_DetailInfo.getRowCount() > rowIndex) {
    switch (columnId) {
      case "cust":
        if (rowJson.cust.trim() != "" && rowJson.cust != scwin.oldValue) {
          scwin.f_PopUpGrid("Customer", rowIndex, "T", "F");
        }
        break;
      case "liner":
        if (rowJson.liner.trim() != "" && rowJson.liner != scwin.oldValue) {
          scwin.f_PopUpGrid("Liner", rowIndex, "T", "F");
        }
        break;
      case "portFrom":
        if (rowJson.portFrom.trim() != "" && rowJson.portFrom != scwin.oldValue) {
          scwin.f_PopUpGrid("Loading", rowIndex, "T", "F");
        }
        break;
      case "portTo":
        if (rowJson.portTo.trim() != "" && rowJson.portTo != scwin.oldValue) {
          scwin.f_PopUpGrid("Discharge", rowIndex, "T", "F");
        }
        break;
      case "item":
        if (rowJson.item.trim() != "" && rowJson.item != scwin.oldValue) {
          scwin.f_PopUpGrid("Item", rowIndex, "T", "F");
        }
        break;
      case "fcode":
        if (rowJson.fcode.trim() != "" && rowJson.fcode != scwin.oldValue) {
          ds_DetailInfo.setCellData(rowIndex, "selpchItemCd", "");
          scwin.f_PopUpGrid("Freight", rowIndex, "T", "F");
        }
        break;
      case "type":
        if (rowJson.type.trim() != "" && rowJson.type != scwin.oldValue) {
          scwin.f_PopUpGrid("CNTR_TYPE", rowIndex, "T", "F");
        }
        break;
      case "curr":
        if (rowJson.curr.trim() != "" && rowJson.curr != scwin.oldValue) {
          scwin.f_PopUpGrid("Currency", rowIndex, "T", "F");
        }
        break;
      default:
        break;
    }
  }
};
